  VALUES ?league {
    wd:Q447247 wd:Q17733
  }
  ?season wdt:P179 ?league .
  ?season wdt:P3967 ?finalEvent .
  ?finalEvent wdt:P1344 ?club .
}
GROUP BY ?club
ORDER BY DESC(?count)
LIMIT 1

SELECT ?races WHERE {
  ?season wdt:P31 wd:Q211975 ; wdt:P3924 wd:Q9673 ; wdt:P580 ?start ; wdt:P1113 ?races .
  FILTER(YEAR(?start) > 2015)
}
ORDER BY ASC(?races)
LIMIT 1

SELECT ?totalMinutes WHERE {
  {
    ?game wdt:P1444 wd:Q334634 .
    ?game wdt:P1445 wd:Q650840
  } UNION {
    ?game wdt:P1444 wd:Q650840 .
    ?game wdt:P1445 wd:Q334634
  }
  .
  ?game wdt:P2047 ?duration .
  BIND((COALESCE(REPLACE(?duration , '.*T([0-9]+)H.*' , '$1' , 'i') , 0) * 60 + COALESCE(REPLACE(?duration , '.*T([0-9]+)M.*' , '$1' , 'i') , 0)) AS ?totalMinutes)
}
ORDER BY ?totalMinutes
OFFSET 2
LIMIT 1

SELECT ?duration WHERE {
  {
    wd:Q2413623 p:P39 ?statement
  } UNION {
    wd:Q369770 p:P39 ?statement
  }
  ?statement ps:P39 ?position ; pq:P580 ?startTime ; pq:P582 ?endTime .
  BIND(xsd:integer(SUBSTR(STR(?endTime) , 1 , 4)) AS ?endYear)
  BIND(xsd:integer(SUBSTR(STR(?startTime) , 1 , 4)) AS ?startYear)
  BIND(?endYear - ?startYear AS ?duration)
  FILTER(?duration > 0)
}
ORDER BY DESC(?duration)
OFFSET 4
LIMIT 1

SELECT ?game ?attendance ?year WHERE {
  VALUES ?dodger {
    wd:Q334634
  }
  VALUES ?phillies {
    wd:Q650840
  }
  VALUES ?nlcs {
    wd:Q1363275
  }
  ?game wdt:P31 wd:Q7184551 ; wdt:P710 ?dodger ; wdt:P710 ?phillies ; wdt:P1216507 ?attendance ; wdt:P585 ?date .
  ?game wdt:P1995 / wdt:P31 ?nlcs .
  BIND(YEAR(?date) AS ?year)
  FILTER(?year IN(1977 , 1978 , 2008 , 2009))
}
ORDER BY ASC(?attendance)

SELECT ?raceLabel(ROUND(?timeSec * 1000) AS ?timeMs) WHERE {
  VALUES ?race {
    wd:Q19704270 wd:Q23045166
  }
  ?race p:P8437 ?result ; rdfs:label ?raceLabel .
  ?result ps:P8437 wd:Q9673 ; pq:P4849 ?timeSec ; pq:P5062 wd:Q419128 .
  FILTER(LANG(?raceLabel) = 'en')
}
ORDER BY ASC(?timeMs)
LIMIT 2

SELECT ?attendance WHERE {
  VALUES ?series {
    wd:Q3511178 wd:Q14870260 wd:Q56692089
  }
  ?series wdt:P527 ?game .
  ?game wdt:P1109 ?attendance .
  FILTER(isNumeric(?attendance))
}
ORDER BY ASC(?attendance)
OFFSET 2
LIMIT 1

SELECT(SUM(xsd:integer(REPLACE(STR(?attendance) , ',' , ''))) AS ?totalAttendance) WHERE {
  VALUES ?playoffType {
    wd:Q755589 wd:Q633904 wd:Q269350 wd:Q3819853
  }
  ?series wdt:P31 ?playoffType ; wdt:P710 wd:Q504309 .
  ?game wdt:P361 ?series ; wdt:P10833 ?attendance .
  FILTER(BOUND(?attendance) &&(REGEX(STR(?attendance) , '^\\d+,\\d+$') || DATATYPE(?attendance) = xsd:integer))
}
GROUP BY ?series
ORDER BY ASC(?totalAttendance)
LIMIT 1
OFFSET 2

SELECT ?club(COUNT(?final) AS ?count) WHERE {
  VALUES ?club {
    wd:Q3044572 wd:Q249679
  }
  ?final wdt:P31 wd:Q2759594 .
  ?final wdt:P710 ?club .
}
GROUP BY ?club

SELECT ?attendance WHERE {
  VALUES(?home ?away) {(wd:Q334634 wd:Q650840)(wd:Q650840 wd:Q334634)
  }
  ?game wdt:P1995 ?home ; wdt:P1996 ?away ; wdt:P1110 ?attendance .
  BIND(xsd:integer(REPLACE(STR(?attendance) , "[^0-9]" , "")) AS ?attNum)
  FILTER(?attNum > 0)
}
ORDER BY DESC(?attNum)
LIMIT 1
OFFSET 2

SELECT ?attendance WHERE {
  ?series wdt:P31 ?seriesType ; wdt:P585 ?seriesTime ; wdt:P710 wd:Q504309 .
  VALUES ?seriesType {
    wd:Q160237 wd:Q191121
  }
  VALUES ?year {
    1982 2006 2011 2013
  }
  FILTER(YEAR(?seriesTime) = ?year)
  FILTER((?seriesType = wd:Q160237 && ?year = 2011) ||(?seriesType = wd:Q191121))
  ?series wdt:P361 ?game .
  ?game wdt:P1110 ?attendance .
  FILTER(BOUND(?attendance) && REGEX(STR(?attendance) , "^\\d+,\\d+$"))
  BIND(REPLACE(STR(?attendance) , "," , "") AS ?cleaned)
  BIND(xsd:integer(?cleaned) AS ?numAttendance)
}
ORDER BY DESC(?numAttendance)
LIMIT 1

SELECT ?attendance WHERE {
  VALUES ?series {
    wd:Q3511262 wd:Q3511261
  }
  ?series wdt:P527 ?game .
  ?game wdt:P1110 ?attendance .
  FILTER(CONTAINS(?attendance , '56000'))
}
ORDER BY DESC(xsd:integer(REPLACE(STR(?attendance) , ',' , '')))
LIMIT 1

SELECT ?attendance WHERE {
  VALUES ?team {
    wd:Q213959 wd:Q207841
  }
  .
  ?game wdt:P710 ?team ; wdt:P1110 ?attendance ; wdt:P580 ?date ; wdt:P31 wd:Q13406554 .
  FILTER(?date >= "2013-10-12" ^^ xsd:date && ?date <= "2013-10-19" ^^ xsd:date)
}
GROUP BY ?attendance
HAVING(COUNT(DISTINCT ?team) = 2)
ORDER BY ASC(xsd:integer(?attendance))
LIMIT 3

SELECT ?disciplineLabel ?playerLabel ?height WHERE {
  wd:Q799589 wdt:P527 ?discipline .
  ?discipline wdt:P1346 | wdt:P1614 | wdt:P1615 ?player .
  ?player wdt:P2048 ?height .
  SERVICE wikibase:label {
    ?discipline rdfs:label ?disciplineLabel .
    ?player rdfs:label ?playerLabel .
    FILTER(LANG(?disciplineLabel) = "en" && LANG(?playerLabel) = "en")
  }
}
ORDER BY DESC(?height)
LIMIT 3

SELECT ?races ?year WHERE {
  VALUES ?year {
    2008 2015 2017 2018 2019
  }
  ?season wdt:P31 wd:Q137604 .
  ?season wdt:P1346 wd:Q9673 .
  ?season wdt:P1534 ?races .
  ?season wdt:P580 ?startTime .
  FILTER(YEAR(?startTime) = ?year)
}
ORDER BY DESC(?races)
LIMIT 1
OFFSET 2

SELECT ?attendance WHERE {
  VALUES ?series {
    wd:Q56692089 wd:Q14870260 wd:Q3511178
  }
  ?series p:P276 / pq:P1110 ?attendance .
}
